void countdown(int n) {
    if (n == 0) {
        printf("발사!");
        return;
    }
    printf("%d", n);
    countdown(n - 1);
}

countdown(3);

int factorial(int n) {
    if (n <= 1) return 1;
    return n * factorial(n - 1);
}

printf("%d", factorial(4));

int factorial(int n) {
